import React, { useMemo, useState } from 'react';
import { createRoot } from 'react-dom/client';
import { AlertTriangle, CheckCircle2, FlaskConical, Leaf, Menu, Microscope, ShieldAlert, Sparkles, X } from 'lucide-react';
import './styles.css';

const API_BASE = import.meta.env.VITE_API_BASE_URL || 'http://localhost:5000';

const fields = [
  ['cap_shape', 'Cap shape', ['bell', 'conical', 'convex', 'flat', 'knobbed', 'sunken']],
  ['cap_surface', 'Cap surface', ['fibrous', 'grooves', 'scaly', 'smooth']],
  ['cap_color', 'Cap color', ['brown', 'buff', 'cinnamon', 'gray', 'green', 'pink', 'purple', 'red', 'white', 'yellow']],
  ['bruises', 'Bruises', ['yes', 'no']],
  ['odor', 'Odor', ['almond', 'anise', 'creosote', 'fishy', 'foul', 'musty', 'none', 'pungent', 'spicy']],
  ['gill_attachment', 'Gill attachment', ['attached', 'descending', 'free', 'notched']],
  ['gill_spacing', 'Gill spacing', ['close', 'crowded', 'distant']],
  ['gill_size', 'Gill size', ['broad', 'narrow']],
  ['gill_color', 'Gill color', ['black', 'brown', 'buff', 'chocolate', 'gray', 'green', 'orange', 'pink', 'purple', 'red', 'white', 'yellow']],
  ['stalk_shape', 'Stalk shape', ['enlarging', 'tapering']],
  ['stalk_root', 'Stalk root', ['bulbous', 'club', 'cup', 'equal', 'rhizomorphs', 'rooted', 'missing']],
  ['ring_type', 'Ring type', ['cobwebby', 'evanescent', 'flaring', 'large', 'none', 'pendant', 'sheathing', 'zone']],
  ['spore_print_color', 'Spore print color', ['black', 'brown', 'buff', 'chocolate', 'green', 'orange', 'purple', 'white', 'yellow']],
  ['habitat', 'Habitat', ['grasses', 'leaves', 'meadows', 'paths', 'urban', 'waste', 'woods']],
];

const starter = Object.fromEntries(fields.map(([name, , options]) => [name, options[0]]));
starter.odor = 'none';
starter.gill_size = 'broad';
starter.habitat = 'woods';

function App() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [form, setForm] = useState(starter);
  const [result, setResult] = useState(null);
  const [errors, setErrors] = useState({});
  const [status, setStatus] = useState('idle');

  const completion = useMemo(() => {
    const filled = Object.values(form).filter(Boolean).length;
    return Math.round((filled / fields.length) * 100);
  }, [form]);

  async function submitPrediction(event) {
    event.preventDefault();
    setStatus('loading');
    setErrors({});
    setResult(null);

    try {
      const response = await fetch(`${API_BASE}/api/predict`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      });
      const data = await response.json();
      if (!response.ok) {
        setErrors(data.fields || { form: data.error || 'Prediction failed.' });
        setStatus('error');
        return;
      }
      setResult(data);
      setStatus('success');
    } catch (error) {
      setErrors({ form: `Could not reach Flask API at ${API_BASE}. Start the backend and try again.` });
      setStatus('error');
    }
  }

  function updateField(name, value) {
    setForm((current) => ({ ...current, [name]: value }));
  }

  return (
    <>
      <header className="site-header">
        <a className="brand" href="#top" aria-label="Mushroom Detector home">
          <span className="brand-mark"><Microscope size={24} /></span>
          <span>Mushroom Detector</span>
        </a>
        <button className="menu-button" onClick={() => setMobileOpen(!mobileOpen)} aria-expanded={mobileOpen} aria-controls="site-nav">
          {mobileOpen ? <X /> : <Menu />}<span className="sr-only">Toggle navigation</span>
        </button>
        <nav id="site-nav" className={mobileOpen ? 'open' : ''}>
          <a href="#detector">Detector</a>
          <a href="#signals">Signals</a>
          <a href="#safety">Safety</a>
        </nav>
      </header>

      <main id="top">
        <section className="hero">
          <div className="hero-copy">
            <p className="eyebrow"><Sparkles size={16} /> Field trait risk scanner</p>
            <h1>Identify risky mushroom patterns before they reach the basket.</h1>
            <p className="hero-text">A React and Flask demo that turns visible mushroom characteristics into an instant edibility risk estimate with clear reasoning.</p>
            <div className="hero-actions">
              <a className="primary-action" href="#detector">Start prediction</a>
              <a className="secondary-action" href="#safety">Read safety note</a>
            </div>
          </div>
          <div className="specimen-board" aria-label="Mushroom analysis preview">
            <div className="scan-ring"><div className="mushroom-illustration"><span /></div></div>
            <div className="metric-card top"><span>Spore risk</span><strong>{form.spore_print_color}</strong></div>
            <div className="metric-card bottom"><span>Profile complete</span><strong>{completion}%</strong></div>
            <div className="trait-strip"><span>odor</span><span>gills</span><span>habitat</span><span>bruising</span></div>
          </div>
        </section>

        <section id="detector" className="detector-section">
          <div className="section-heading">
            <p className="eyebrow"><FlaskConical size={16} /> Prediction lab</p>
            <h2>Enter observed traits</h2>
            <p>Choose the closest match for each field. The backend validates every value before scoring.</p>
          </div>

          <div className="detector-layout">
            <form className="predictor-card" onSubmit={submitPrediction}>
              <div className="form-grid">
                {fields.map(([name, label, options]) => (
                  <label key={name} className="field">
                    <span>{label}</span>
                    <select value={form[name]} onChange={(event) => updateField(name, event.target.value)}>
                      {options.map((option) => <option key={option} value={option}>{title(option)}</option>)}
                    </select>
                    {errors[name] && <small className="field-error">{errors[name]}</small>}
                  </label>
                ))}
              </div>
              {errors.form && <p className="form-error">{errors.form}</p>}
              <button className="submit-button" disabled={status === 'loading'}>
                {status === 'loading' ? 'Analyzing specimen…' : 'Predict mushroom risk'}
              </button>
            </form>

            <aside className={`result-panel ${result?.prediction || ''}`}>
              {!result ? (
                <div className="empty-result">
                  <ShieldAlert size={44} />
                  <h3>Awaiting specimen</h3>
                  <p>Your prediction, confidence, probability split, and top reasons will appear here.</p>
                </div>
              ) : (
                <>
                  <p className="result-label">Prediction</p>
                  <h3>{title(result.prediction)}</h3>
                  <div className="probability">
                    <span style={{ width: `${result.poisonous_probability}%` }} />
                  </div>
                  <div className="probability-row"><span>Edible {result.edible_probability}%</span><span>Poisonous {result.poisonous_probability}%</span></div>
                  <div className="confidence"><strong>{result.confidence}%</strong><span>confidence · {result.risk_level} risk</span></div>
                  <ul className="reason-list">
                    {result.reasons.map((reason) => <li key={reason}>{result.prediction === 'edible' ? <CheckCircle2 size={18} /> : <AlertTriangle size={18} />}{reason}</li>)}
                  </ul>
                  <p className="disclaimer">{result.disclaimer}</p>
                </>
              )}
            </aside>
          </div>
        </section>

        <section id="signals" className="signals-section">
          <article><Leaf /><h3>Structured observations</h3><p>Cap, gill, stalk, ring, spore, odor, bruising, and habitat signals are scored together instead of relying on a single trait.</p></article>
          <article><Microscope /><h3>Explainable output</h3><p>The API returns practical reasons so users can see which features pushed the result toward risk or caution.</p></article>
          <article><ShieldAlert /><h3>Safety first</h3><p>This is a software demo, not foraging advice. Unknown wild mushrooms should be checked by a qualified mycologist.</p></article>
        </section>

        <section id="safety" className="safety-band">
          <h2>Important safety note</h2>
          <p>Mushroom poisoning can be fatal and many edible and poisonous species look similar. Never consume a wild mushroom because an app says it is edible.</p>
        </section>
      </main>
    </>
  );
}

function title(value) {
  return value.replace(/_/g, ' ').replace(/\b\w/g, (letter) => letter.toUpperCase());
}

createRoot(document.getElementById('root')).render(<App />);

