          {session && <button className="nav-logout" onClick={logout}><LogOut size={16} /> Logout</button>}
        </nav>
      </header>

      <main id="top">
        <section className="hero">
          <div className="hero-copy">
            <p className="eyebrow"><Sparkles size={16} /> Private field trait scanner</p>
            <h1>Login, record traits, and check mushroom risk.</h1>
            <p className="hero-text">Mushroom Detector now includes account registration, secure password hashing, session tokens, protected predictions, and explainable results.</p>
            <div className="hero-actions"><a className="primary-action" href={session ? '#detector' : '#account'}>{session ? 'Start prediction' : 'Create account'}</a><a className="secondary-action" href="#safety">Read safety note</a></div>
          </div>
          <div className="specimen-board" aria-label="Mushroom analysis preview">
            <div className="scan-ring"><div className="mushroom-illustration"><span /></div></div>
            <div className="metric-card top"><span>Session</span><strong>{session ? 'active' : 'locked'}</strong></div>
            <div className="metric-card bottom"><span>Profile complete</span><strong>{completion}%</strong></div>
            <div className="trait-strip"><span>login</span><span>traits</span><span>risk</span><span>report</span></div>
          </div>
        </section>

        <section id="account" className="account-section">
          <div className="section-heading"><p className="eyebrow"><LockKeyhole size={16} /> Account access</p><h2>{session ? `Welcome, ${session.user.name}` : 'Login or register'}</h2><p>Predictions are protected. Create an account or sign in to use the detector.</p></div>
          {session ? (
            <div className="account-card signed-in"><CheckCircle2 /><div><h3>Signed in as {session.user.email}</h3><p>Your bearer session token is stored locally in this browser for the demo.</p></div><button className="secondary-action" onClick={logout}>Logout</button></div>
          ) : (
            <form className="account-card" onSubmit={submitAuth}>
              <div className="auth-tabs"><button type="button" className={authMode === 'login' ? 'active' : ''} onClick={() => setAuthMode('login')}><LockKeyhole size={17} /> Login</button><button type="button" className={authMode === 'register' ? 'active' : ''} onClick={() => setAuthMode('register')}><UserPlus size={17} /> Register</button></div>
              {authMode === 'register' && <label className="field"><span>Name</span><input value={authForm.name} onChange={(e) => setAuthForm({ ...authForm, name: e.target.value })} placeholder="Ada Forager" />{authErrors.name && <small className="field-error">{authErrors.name}</small>}</label>}
              <label className="field"><span>Email</span><input type="email" value={authForm.email} onChange={(e) => setAuthForm({ ...authForm, email: e.target.value })} placeholder="you@example.com" />{authErrors.email && <small className="field-error">{authErrors.email}</small>}</label>
              <label className="field"><span>Password</span><input type="password" value={authForm.password} onChange={(e) => setAuthForm({ ...authForm, password: e.target.value })} placeholder="At least 8 characters" />{authErrors.password && <small className="field-error">{authErrors.password}</small>}</label>
              {authErrors.form && <p className="form-error">{authErrors.form}</p>}
              <button className="submit-button" disabled={authStatus === 'loading'}>{authStatus === 'loading' ? 'Please wait…' : authMode === 'register' ? 'Create account' : 'Login'}</button>
            </form>
          )}
        </section>

        <section id="detector" className="detector-section">
          <div className="section-heading"><p className="eyebrow"><FlaskConical size={16} /> Prediction lab</p><h2>Enter observed traits</h2><p>Choose the closest match for each field. The backend validates every value and requires your login token before scoring.</p></div>
          <div className="detector-layout">
            <form className="predictor-card" onSubmit={submitPrediction}>
              <div className="form-grid">{fields.map(([name, label, options]) => <label key={name} className="field"><span>{label}</span><select value={form[name]} onChange={(event) => updateField(name, event.target.value)}>{options.map((option) => <option key={option} value={option}>{title(option)}</option>)}</select>{errors[name] && <small className="field-error">{errors[name]}</small>}</label>)}</div>
              {errors.form && <p className="form-error">{errors.form}</p>}
              <button className="submit-button" disabled={status === 'loading'}>{status === 'loading' ? 'Analyzing specimen…' : session ? 'Predict mushroom risk' : 'Login required'}</button>
            </form>
            <aside className={`result-panel ${result?.prediction || ''}`}>{!result ? <div className="empty-result"><ShieldAlert size={44} /><h3>{session ? 'Awaiting specimen' : 'Locked detector'}</h3><p>{session ? 'Your prediction, confidence, probability split, and top reasons will appear here.' : 'Login or register above to unlock protected predictions.'}</p></div> : <><p className="result-label">Prediction for {result.user?.name}</p><h3>{title(result.prediction)}</h3><div className="probability"><span style={{ width: `${result.poisonous_probability}%` }} /></div><div className="probability-row"><span>Edible {result.edible_probability}%</span><span>Poisonous {result.poisonous_probability}%</span></div><div className="confidence"><strong>{result.confidence}%</strong><span>confidence · {result.risk_level} risk</span></div><ul className="reason-list">{result.reasons.map((reason) => <li key={reason}>{result.prediction === 'edible' ? <CheckCircle2 size={18} /> : <AlertTriangle size={18} />}{reason}</li>)}</ul><p className="disclaimer">{result.disclaimer}</p></>}</aside>
          </div>
        </section>

        <section id="signals" className="signals-section"><article><Leaf /><h3>Structured observations</h3><p>Cap, gill, stalk, ring, spore, odor, bruising, and habitat signals are scored together instead of relying on a single trait.</p></article><article><Microscope /><h3>Protected API</h3><p>Passwords are hashed, sessions use random bearer tokens, and prediction requests require authentication.</p></article><article><ShieldAlert /><h3>Safety first</h3><p>This is a software demo, not foraging advice. Unknown wild mushrooms should be checked by a qualified mycologist.</p></article></section>
        <section id="safety" className="safety-band"><h2>Important safety note</h2><p>Mushroom poisoning can be fatal and many edible and poisonous species look similar. Never consume a wild mushroom because an app says it is edible.</p></section>
      </main>
    </>
  );
}

function title(value) { return value.replace(/_/g, ' ').replace(/\b\w/g, (letter) => letter.toUpperCase()); }

createRoot(document.getElementById('root')).render(<App />);

