.account-card.signed-in > svg { color: var(--safe); width: 2.5rem; height: 2.5rem; }
.account-card h3, .account-card p { margin: 0; }
.auth-tabs { display: inline-flex; width: fit-content; padding: .35rem; border-radius: 999px; background: rgba(59,36,22,.08); }
.auth-tabs button { display: inline-flex; align-items: center; gap: .35rem; border: 0; border-radius: 999px; padding: .65rem 1rem; background: transparent; font-weight: 900; color: rgba(32,23,16,.7); cursor: pointer; }
.auth-tabs button.active { color: #fff; background: var(--soil); }
.predictor-card { border-radius: 2rem; padding: clamp(1rem, 3vw, 2rem); }
.form-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 1rem; }
.field { display: flex; flex-direction: column; gap: .45rem; font-weight: 900; color: var(--soil); }
.field select, .field input { width: 100%; border: 1px solid rgba(59,36,22,.18); border-radius: 1rem; background: #fffdf7; padding: .85rem .9rem; color: var(--ink); outline: none; }
.field select:focus, .field input:focus { border-color: var(--spore); box-shadow: 0 0 0 4px rgba(216,111,54,.15); }
.field-error, .form-error { color: var(--danger); font-weight: 800; }
.form-error { margin: 1rem 0 0; }
.submit-button { width: 100%; margin-top: 1.4rem; cursor: pointer; }

