from __future__ import annotations

import os
import re
import secrets
import sqlite3
import tempfile
from dataclasses import dataclass
from functools import wraps
from pathlib import Path
from typing import Any, Callable

import numpy as np
from tensorflow import keras

from flask import Flask, jsonify, request
from flask_cors import CORS
from PIL import Image, ImageStat, UnidentifiedImageError
from werkzeug.security import check_password_hash, generate_password_hash

DB_PATH = Path(os.environ.get("MUSHROOM_DB_PATH", Path(__file__).with_name("mushroom_detector.db")))
MODEL_PATH = Path(os.environ.get("MUSHROOM_MODEL_PATH", Path(__file__).with_name("model") / "mushroom_classifier.keras"))
MODEL_IMAGE_SIZE = (180, 180)
MODEL_CLASSES = ["edible_mushroom", "poisonous_mushroom"]
MODEL: Any | None = None
MODEL_LOAD_ERROR: str | None = None
TOKEN_BYTES = 32


@dataclass(frozen=True)
class MushroomSample:
    cap_shape: str
    cap_surface: str
    cap_color: str
    bruises: str
    odor: str
    gill_attachment: str
    gill_spacing: str
    gill_size: str
    gill_color: str
    stalk_shape: str
    stalk_root: str
    ring_type: str
    spore_print_color: str
    habitat: str


VALID_OPTIONS: dict[str, set[str]] = {
    "cap_shape": {"bell", "conical", "convex", "flat", "knobbed", "sunken"},
    "cap_surface": {"fibrous", "grooves", "scaly", "smooth"},
    "cap_color": {"brown", "buff", "cinnamon", "gray", "green", "pink", "purple", "red", "white", "yellow"},
    "bruises": {"yes", "no"},
    "odor": {"almond", "anise", "creosote", "fishy", "foul", "musty", "none", "pungent", "spicy"},
    "gill_attachment": {"attached", "descending", "free", "notched"},
    "gill_spacing": {"close", "crowded", "distant"},
    "gill_size": {"broad", "narrow"},
    "gill_color": {"black", "brown", "buff", "chocolate", "gray", "green", "orange", "pink", "purple", "red", "white", "yellow"},
    "stalk_shape": {"enlarging", "tapering"},
    "stalk_root": {"bulbous", "club", "cup", "equal", "rhizomorphs", "rooted", "missing"},
    "ring_type": {"cobwebby", "evanescent", "flaring", "large", "none", "pendant", "sheathing", "zone"},
    "spore_print_color": {"black", "brown", "buff", "chocolate", "green", "orange", "purple", "white", "yellow"},
    "habitat": {"grasses", "leaves", "meadows", "paths", "urban", "waste", "woods"},
}


DANGER_WEIGHTS = {
    "odor": {"foul": 30, "fishy": 26, "spicy": 25, "pungent": 24, "creosote": 22, "musty": 18, "none": 5, "almond": -12, "anise": -12},
    "spore_print_color": {"green": 34, "white": 12, "chocolate": 8, "black": -5, "brown": -4},
    "gill_size": {"narrow": 18, "broad": -7},
    "gill_color": {"buff": 22, "green": 20, "white": 7, "pink": -8, "brown": -5},
    "bruises": {"no": 8, "yes": -8},
    "ring_type": {"none": 11, "large": 10, "pendant": -7},
    "stalk_root": {"missing": 13, "bulbous": 8, "club": -5, "rooted": -8},
    "habitat": {"woods": 6, "paths": 5, "waste": 9, "grasses": -4, "meadows": -5},
    "cap_color": {"yellow": 6, "white": 4, "red": 5, "brown": -3},
}


FIELD_LABELS = {key: key.replace("_", " ").title() for key in VALID_OPTIONS}


def get_db() -> sqlite3.Connection:
    connection = sqlite3.connect(DB_PATH)
    connection.row_factory = sqlite3.Row
    return connection


def init_db() -> None:
    DB_PATH.parent.mkdir(parents=True, exist_ok=True)
    with get_db() as db:
        db.executescript(
            """
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                email TEXT NOT NULL UNIQUE,
                password_hash TEXT NOT NULL,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS sessions (
                token TEXT PRIMARY KEY,
                user_id INTEGER NOT NULL,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
            );
            """
        )


def public_user(row: sqlite3.Row) -> dict[str, Any]:
    return {"id": row["id"], "name": row["name"], "email": row["email"]}


def issue_token(user_id: int) -> str:
    token = secrets.token_urlsafe(TOKEN_BYTES)
    with get_db() as db:
        db.execute("INSERT INTO sessions (token, user_id) VALUES (?, ?)", (token, user_id))
    return token


def get_current_user() -> sqlite3.Row | None:
    auth = request.headers.get("Authorization", "")
    if not auth.startswith("Bearer "):
        return None
    token = auth.removeprefix("Bearer ").strip()
    if not token:
        return None
    with get_db() as db:
        return db.execute(
            """
            SELECT users.id, users.name, users.email
            FROM sessions
            JOIN users ON users.id = sessions.user_id
            WHERE sessions.token = ?
            """,
            (token,),
        ).fetchone()


def require_auth(view: Callable[..., Any]) -> Callable[..., Any]:
    @wraps(view)
    def wrapped(*args: Any, **kwargs: Any) -> Any:
        user = get_current_user()
        if user is None:
            return jsonify({"error": "Authentication required."}), 401
        return view(user, *args, **kwargs)

    return wrapped


def validate_auth_payload(payload: Any, *, registering: bool) -> tuple[dict[str, str], dict[str, str]]:
    if not isinstance(payload, dict):
        return {"form": "Request body must be JSON."}, {}

    errors: dict[str, str] = {}
    cleaned: dict[str, str] = {}
    if registering:
        name = str(payload.get("name", "")).strip()
        if len(name) < 2:
            errors["name"] = "Name must be at least 2 characters."
        else:
            cleaned["name"] = name[:80]

    email = str(payload.get("email", "")).strip().lower()
    if not re.fullmatch(r"[^@\s]+@[^@\s]+\.[^@\s]+", email):
        errors["email"] = "Enter a valid email address."
    else:
        cleaned["email"] = email

    password = str(payload.get("password", ""))
    if len(password) < 8:
        errors["password"] = "Password must be at least 8 characters."
    else:
        cleaned["password"] = password

    return errors, cleaned


def create_app() -> Flask:
    init_db()
    load_model_once()
    app = Flask(__name__)
    CORS(app, resources={r"/api/*": {"origins": "*"}})

    @app.get("/api/health")
    def health() -> tuple[dict[str, str], int]:
        return {"status": "ok", "service": "mushroom-detector"}, 200

    @app.post("/api/auth/register")
    def register() -> tuple[Any, int]:
        errors, cleaned = validate_auth_payload(request.get_json(silent=True), registering=True)
        if errors:
            return jsonify({"error": "Validation failed.", "fields": errors}), 422

        try:
            with get_db() as db:
                cursor = db.execute(
                    "INSERT INTO users (name, email, password_hash) VALUES (?, ?, ?)",
                    (cleaned["name"], cleaned["email"], generate_password_hash(cleaned["password"])),
                )
                user_id = int(cursor.lastrowid)
                user = db.execute("SELECT id, name, email FROM users WHERE id = ?", (user_id,)).fetchone()
        except sqlite3.IntegrityError:
            return jsonify({"error": "Validation failed.", "fields": {"email": "An account with this email already exists."}}), 409

        return jsonify({"token": issue_token(user_id), "user": public_user(user)}), 201

    @app.post("/api/auth/login")
    def login() -> tuple[Any, int]:
        errors, cleaned = validate_auth_payload(request.get_json(silent=True), registering=False)
        if errors:
            return jsonify({"error": "Validation failed.", "fields": errors}), 422

        with get_db() as db:
            user = db.execute("SELECT id, name, email, password_hash FROM users WHERE email = ?", (cleaned["email"],)).fetchone()

        if user is None or not check_password_hash(user["password_hash"], cleaned["password"]):
            return jsonify({"error": "Invalid email or password."}), 401

        return jsonify({"token": issue_token(int(user["id"])), "user": public_user(user)}), 200

    @app.post("/api/auth/logout")
    def logout() -> tuple[Any, int]:
        auth = request.headers.get("Authorization", "")
        token = auth.removeprefix("Bearer ").strip() if auth.startswith("Bearer ") else ""
        if token:
            with get_db() as db:
                db.execute("DELETE FROM sessions WHERE token = ?", (token,))
        return jsonify({"status": "ok"}), 200

    @app.get("/api/auth/me")
    @require_auth
    def me(user: sqlite3.Row) -> tuple[Any, int]:
        return jsonify({"user": public_user(user)}), 200

    @app.get("/api/options")
    def options() -> tuple[Any, int]:
        return jsonify({field: sorted(values) for field, values in VALID_OPTIONS.items()}), 200

    @app.post("/api/predict")
    @require_auth
    def predict(user: sqlite3.Row) -> tuple[Any, int]:
        uploaded = request.files.get("image")
        if uploaded is None or uploaded.filename == "":
            return jsonify({"error": "Upload a mushroom image using the 'image' form field."}), 400
        if uploaded.mimetype not in {"image/jpeg", "image/png", "image/webp"}:
            return jsonify({"error": "Only JPEG, PNG, and WebP images are supported."}), 415

        suffix = Path(uploaded.filename).suffix or ".jpg"
        with tempfile.NamedTemporaryFile(suffix=suffix, delete=False) as temp_file:
            uploaded.save(temp_file)
            temp_path = Path(temp_file.name)

        try:
            image = Image.open(temp_path)
            image.verify()
            image = Image.open(temp_path).convert("RGB")
        except (UnidentifiedImageError, OSError):
            temp_path.unlink(missing_ok=True)
            return jsonify({"error": "The uploaded file is not a valid image."}), 400

        model_result = predict_with_model(temp_path)
        temp_path.unlink(missing_ok=True)
        score, reasons, signals = analyze_mushroom_image(image)
        if model_result is not None:
            probability_poisonous = round(model_result["poisonous_probability"])
            reasons = [f"Keras classifier predicted {model_result['predicted_class'].replace('_', ' ')}."] + reasons[:4]
            signals["model_source"] = "keras"
        else:
            probability_poisonous = max(5, min(95, round(score)))
            signals["model_source"] = "heuristic_fallback"
            if MODEL_LOAD_ERROR:
                signals["model_status"] = MODEL_LOAD_ERROR
        probability_poisonous = max(1, min(99, probability_poisonous))
        is_poisonous = probability_poisonous >= 50

        return jsonify(
            {
                "prediction": "poisonous" if is_poisonous else "edible",
                "confidence": probability_poisonous if is_poisonous else 100 - probability_poisonous,
                "poisonous_probability": probability_poisonous,
                "edible_probability": 100 - probability_poisonous,
                "risk_level": risk_level(probability_poisonous),
                "reasons": reasons,
                "vision_signals": signals,
                "model": model_result,
                "user": public_user(user),
                "disclaimer": "Educational computer-vision demo only. Never eat wild mushrooms based on an app prediction.",
            }
        ), 200

    return app


def load_model_once() -> None:
    global MODEL, MODEL_LOAD_ERROR
    if MODEL is not None or MODEL_LOAD_ERROR is not None:
        return
    if not MODEL_PATH.exists():
        MODEL_LOAD_ERROR = f"Keras model not found at {MODEL_PATH}. Using heuristic fallback."
        return
    try:
        MODEL = keras.models.load_model(MODEL_PATH)
        MODEL_LOAD_ERROR = None
    except Exception as exc:  # pragma: no cover - depends on local ML runtime
        MODEL_LOAD_ERROR = f"Could not load Keras model: {exc}. Using heuristic fallback."


def predict_with_model(image_path: Path) -> dict[str, Any] | None:
    if MODEL is None:
        return None
    img = keras.utils.load_img(image_path, target_size=MODEL_IMAGE_SIZE)
    img_array = keras.utils.img_to_array(img)
    img_array = np.expand_dims(img_array, axis=0)
    prediction = MODEL.predict(img_array, verbose=0)
    score = float(keras.ops.sigmoid(prediction[0][0]))
    edible_probability = (1 - score) * 100
    poisonous_probability = score * 100
    if score >= 0.5:
        predicted_class = MODEL_CLASSES[1]
        confidence = poisonous_probability
    else:
        predicted_class = MODEL_CLASSES[0]
        confidence = edible_probability
    return {
        "predicted_class": predicted_class,
        "confidence": confidence,
        "edible_probability": edible_probability,
        "poisonous_probability": poisonous_probability,
    }


def analyze_mushroom_image(image: Image.Image) -> tuple[float, list[str], dict[str, Any]]:
    thumbnail = image.copy()
    thumbnail.thumbnail((320, 320))
    stat = ImageStat.Stat(thumbnail)
