                {errors.form && <p className="form-error">{errors.form}</p>}
                <button className="submit-button" disabled={status === 'loading'}>{status === 'loading' ? 'Scanning image…' : 'Scan mushroom image'}</button>
              </form>
              <ResultPanel result={result} />
            </div>
          </section>
          <section id="signals" className="signals-section"><article><ImageUp /><h3>Camera or upload</h3><p>Users scan a mushroom/object by taking a photo or uploading an existing image from their device.</p></article><article><Microscope /><h3>Vision signals</h3><p>The API extracts brightness, contrast, and color coverage signals to produce an explainable demo prediction.</p></article><article><ShieldAlert /><h3>Safety first</h3><p>This is a computer-vision demo, not foraging advice. Never eat wild mushrooms based on software output.</p></article></section>
