import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { AlertTriangle, Camera, CheckCircle2, ImageUp, Leaf, LockKeyhole, LogOut, Menu, Microscope, ScanLine, ShieldAlert, Sparkles, UserPlus, X } from 'lucide-react';
import './styles.css';

const API_BASE = import.meta.env.VITE_API_BASE_URL || 'http://localhost:5000';
const SESSION_KEY = 'mushroom-detector-session';

function loadSession() {
  try { return JSON.parse(localStorage.getItem(SESSION_KEY)) || null; } catch { return null; }
}

function App() {
  const initialSession = loadSession();
  const [mobileOpen, setMobileOpen] = useState(false);
  const [session, setSession] = useState(initialSession);
  const [page, setPage] = useState(initialSession ? 'app' : 'home');
  const [authMode, setAuthMode] = useState('login');
  const [authForm, setAuthForm] = useState({ name: '', email: '', password: '' });
  const [authErrors, setAuthErrors] = useState({});
  const [authStatus, setAuthStatus] = useState('idle');
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [result, setResult] = useState(null);
  const [errors, setErrors] = useState({});
  const [status, setStatus] = useState('idle');

  function saveSession(nextSession) {
    setSession(nextSession);
    if (nextSession) localStorage.setItem(SESSION_KEY, JSON.stringify(nextSession));
    else localStorage.removeItem(SESSION_KEY);
  }

  async function submitAuth(event) {
    event.preventDefault();
    setAuthStatus('loading');
    setAuthErrors({});
    try {
      const payload = authMode === 'register' ? authForm : { email: authForm.email, password: authForm.password };
      const response = await fetch(`${API_BASE}/api/auth/${authMode}`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
      const data = await response.json();
      if (!response.ok) {
        setAuthErrors(data.fields || { form: data.error || 'Authentication failed.' });
        setAuthStatus('error');
        return;
      }
      saveSession(data);
      setPage('app');
      setAuthStatus('success');
      setAuthForm({ name: '', email: '', password: '' });
    } catch {
      setAuthErrors({ form: `Could not reach Flask API at ${API_BASE}.` });
      setAuthStatus('error');
    }
  }

  async function logout() {
    if (session?.token) await fetch(`${API_BASE}/api/auth/logout`, { method: 'POST', headers: { Authorization: `Bearer ${session.token}` } }).catch(() => {});
    saveSession(null);
    setPage('home');
    setResult(null);
  }

  function handleImage(event) {
    const file = event.target.files?.[0];
    setErrors({});
    setResult(null);
    if (!file) return;
    if (!file.type.startsWith('image/')) {
      setErrors({ form: 'Please choose a valid image file.' });
      return;
    }
    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  }

  async function submitPrediction(event) {
    event.preventDefault();
    if (!session?.token) return setErrors({ form: 'Please login or create an account before scanning.' });
    if (!imageFile) return setErrors({ form: 'Take or upload a mushroom photo first.' });
    setStatus('loading');
    setErrors({});
    setResult(null);

    const body = new FormData();
    body.append('image', imageFile);
    try {
      const response = await fetch(`${API_BASE}/api/predict`, { method: 'POST', headers: { Authorization: `Bearer ${session.token}` }, body });
      const data = await response.json();
      if (!response.ok && data.prediction !== 'scan_failed') {
        if (response.status === 401) saveSession(null);
        setErrors({ form: data.error || 'Scan failed.' });
        setStatus('error');
        return;
      }
      setResult(data);
      setStatus(data.prediction === 'scan_failed' ? 'error' : 'success');
    } catch {
      setErrors({ form: `Could not reach Flask API at ${API_BASE}. Start the backend and try again.` });
      setStatus('error');
    }
  }

  return (
    <>
      <header className="site-header">
        <button className="brand brand-button" onClick={() => setPage(session ? 'app' : 'home')} aria-label="Mushroom Detector home"><span className="brand-mark"><Microscope size={24} /></span><span>Mushroom Detector</span></button>
        <button className="menu-button" onClick={() => setMobileOpen(!mobileOpen)} aria-expanded={mobileOpen} aria-controls="site-nav">{mobileOpen ? <X /> : <Menu />}<span className="sr-only">Toggle navigation</span></button>
        <nav id="site-nav" className={mobileOpen ? 'open' : ''}>{!session && <button onClick={() => setPage('home')}>Home</button>}{!session && <button onClick={() => { setAuthMode('login'); setPage('auth'); }}>Login</button>}{!session && <button onClick={() => { setAuthMode('register'); setPage('auth'); }}>Register</button>}{session && <button onClick={() => setPage('app')}>Detector</button>}{session && <button className="nav-logout" onClick={logout}><LogOut size={16} /> Logout</button>}</nav>
      </header>

      {page === 'home' ? <Landing setPage={setPage} setAuthMode={setAuthMode} /> : page === 'auth' ? (
        <main id="top" className="auth-page">
          <section id="account" className="account-section auth-only">
            <form className="account-card" onSubmit={submitAuth}>
              <div className="auth-tabs"><button type="button" className={authMode === 'login' ? 'active' : ''} onClick={() => setAuthMode('login')}><LockKeyhole size={17} /> Login</button><button type="button" className={authMode === 'register' ? 'active' : ''} onClick={() => setAuthMode('register')}><UserPlus size={17} /> Register</button></div>
              {authMode === 'register' && <label className="field"><span>Name</span><input value={authForm.name} onChange={(e) => setAuthForm({ ...authForm, name: e.target.value })} placeholder="Ada Forager" />{authErrors.name && <small className="field-error">{authErrors.name}</small>}</label>}
              <label className="field"><span>Email</span><input type="email" value={authForm.email} onChange={(e) => setAuthForm({ ...authForm, email: e.target.value })} placeholder="you@example.com" />{authErrors.email && <small className="field-error">{authErrors.email}</small>}</label>
              <label className="field"><span>Password</span><input type="password" value={authForm.password} onChange={(e) => setAuthForm({ ...authForm, password: e.target.value })} placeholder="At least 8 characters" />{authErrors.password && <small className="field-error">{authErrors.password}</small>}</label>
              {authErrors.form && <p className="form-error">{authErrors.form}</p>}
              <button className="submit-button" disabled={authStatus === 'loading'}>{authStatus === 'loading' ? 'Please wait…' : authMode === 'register' ? 'Create account' : 'Login'}</button>
            </form>
          </section>
        </main>
      ) : (
        <main id="top" className="scanner-page">
          <section id="detector" className="detector-section scanner-only">
            <div className="detector-layout">
              <form className="predictor-card scanner-card" onSubmit={submitPrediction}>
                <label className="upload-zone"><input type="file" accept="image/png,image/jpeg,image/webp" capture="environment" onChange={handleImage} /><span className="upload-icon"><Camera /></span><strong>{imageFile ? imageFile.name : 'Take or upload mushroom photo'}</strong><small>Use a clear, close image with cap, stem, and underside visible when possible.</small></label>
                {imagePreview && <img className="image-preview" src={imagePreview} alt="Selected mushroom scan preview" />}
                {errors.form && <p className="form-error">{errors.form}</p>}
                <button className="submit-button" disabled={status === 'loading'}>{status === 'loading' ? 'Scanning image…' : 'Scan mushroom image'}</button>
              </form>
              <ResultPanel result={result} />
            </div>
          </section>
        </main>
      )}
    </>
  );
}

function Landing({ setPage, setAuthMode }) {
