ucational use only.</p></div><nav aria-label="Footer navigation"><button onClick={() => { setAuthMode('login'); setPage('auth'); }}>Login</button><button onClick={() => { setAuthMode('register'); setPage('auth'); }}>Register</button></nav></footer></main>;
